"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[795],{85011(n,e,r){r.r(e),r.d(e,{assets:()=>d,contentTitle:()=>a,default:()=>l,frontMatter:()=>o,metadata:()=>t,toc:()=>p});const t=JSON.parse('{"id":"cpp20/concepts-advanced","title":"Concepts \u9ad8\u7ea7 (\u81ea\u5b9a\u4e49 concept\u3001\u7ec4\u5408\u7ea6\u675f)","description":"C++20 Concepts \u9ad8\u7ea7 (\u81ea\u5b9a\u4e49 concept\u3001\u7ec4\u5408\u7ea6\u675f) \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp20/02-concepts-advanced.md","sourceDirName":"cpp20","slug":"/cpp20/02-concepts-advanced","permalink":"/LearnModernCpp/docs/cpp20/02-concepts-advanced","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp20","permalink":"/LearnModernCpp/docs/tags/cpp-20"},{"inline":true,"label":"concepts_advanced","permalink":"/LearnModernCpp/docs/tags/concepts-advanced"}],"version":"current","sidebarPosition":3,"frontMatter":{"sidebar_position":3,"slug":"02-concepts-advanced","title":"Concepts \u9ad8\u7ea7 (\u81ea\u5b9a\u4e49 concept\u3001\u7ec4\u5408\u7ea6\u675f)","description":"C++20 Concepts \u9ad8\u7ea7 (\u81ea\u5b9a\u4e49 concept\u3001\u7ec4\u5408\u7ea6\u675f) \u6559\u5b66\u793a\u4f8b","tags":["cpp20","concepts_advanced"]},"sidebar":"docs","previous":{"title":"Concepts \u57fa\u7840 (concept\u3001requires\u5b50\u53e5)","permalink":"/LearnModernCpp/docs/cpp20/01-concepts-basics"},"next":{"title":"requires \u8868\u8fbe\u5f0f","permalink":"/LearnModernCpp/docs/cpp20/03-requires-expressions"}}');var c=r(74848),s=r(28453);const o={sidebar_position:3,slug:"02-concepts-advanced",title:"Concepts \u9ad8\u7ea7 (\u81ea\u5b9a\u4e49 concept\u3001\u7ec4\u5408\u7ea6\u675f)",description:"C++20 Concepts \u9ad8\u7ea7 (\u81ea\u5b9a\u4e49 concept\u3001\u7ec4\u5408\u7ea6\u675f) \u6559\u5b66\u793a\u4f8b",tags:["cpp20","concepts_advanced"]},a="Concepts \u9ad8\u7ea7 (\u81ea\u5b9a\u4e49 concept\u3001\u7ec4\u5408\u7ea6\u675f)",d={},p=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function i(n){const e={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,s.R)(),...n.components};return(0,c.jsxs)(c.Fragment,{children:[(0,c.jsx)(e.header,{children:(0,c.jsx)(e.h1,{id:"concepts-\u9ad8\u7ea7-\u81ea\u5b9a\u4e49-concept\u7ec4\u5408\u7ea6\u675f",children:"Concepts \u9ad8\u7ea7 (\u81ea\u5b9a\u4e49 concept\u3001\u7ec4\u5408\u7ea6\u675f)"})}),"\n",(0,c.jsx)(e.p,{children:"C++20 \u6807\u51c6\u5f15\u5165\u7684 Concepts \u9ad8\u7ea7 (\u81ea\u5b9a\u4e49 concept\u3001\u7ec4\u5408\u7ea6\u675f) \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,c.jsx)(e.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,c.jsx)(e.pre,{children:(0,c.jsx)(e.code,{className:"language-cpp",metastring:'title="cpp20/02_concepts_advanced.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: Concepts \u9ad8\u7ea7 (\u81ea\u5b9a\u4e49 concept\u3001\u7ec4\u5408\u7ea6\u675f)\r\n * \u6240\u5c5e\u6807\u51c6: C++20\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: \u9664\u4e86\u4f7f\u7528\u6807\u51c6\u5e93\u63d0\u4f9b\u7684 concept\uff0c\u7a0b\u5e8f\u5458\u53ef\u4ee5\u81ea\u5b9a\u4e49 concept\uff0c\r\n *          \u5e76\u4f7f\u7528\u903b\u8f91\u8fd0\u7b97\u7b26\u5bf9 concept \u8fdb\u884c\u7ec4\u5408\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: \u6807\u51c6\u5e93\u7684\u5185\u7f6e concept \u4e0d\u80fd\u8986\u76d6\u6240\u6709\u573a\u666f\uff0c\r\n *             \u81ea\u5b9a\u4e49 concept \u53ef\u4ee5\u7cbe\u786e\u8868\u8fbe\u9886\u57df\u7279\u6709\u7684\u7c7b\u578b\u7ea6\u675f\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - \u4f7f\u7528 concept \u5173\u952e\u5b57\u5b9a\u4e49\u81ea\u5df1\u7684\u7ea6\u675f\r\n *   - concept \u53ef\u4ee5\u901a\u8fc7 && \u548c || \u8fdb\u884c\u7ec4\u5408\r\n *   - concept \u7ec6\u5316\uff08refinement\uff09\u5141\u8bb8\u66f4\u7279\u5316\u7684 concept \u7ee7\u627f\u7ea6\u675f\r\n *   - subsumption \u89c4\u5219\u51b3\u5b9a\u4e86\u91cd\u8f7d\u89e3\u6790\u65f6\u7684\u4f18\u5148\u7ea7\r\n * ============================================================\r\n */\r\n\r\n#include <concepts>\r\n#include <iostream>\r\n#include <string>\r\n#include <vector>\r\n#include <type_traits>\r\n\r\n// ===================== basic_usage() =====================\r\n\r\n// \u81ea\u5b9a\u4e49 concept\uff1a\u8981\u6c42\u7c7b\u578b\u53ef\u4ee5\u76f8\u52a0\r\ntemplate<typename T>\r\nconcept Addable = requires(T a, T b) {\r\n    { a + b } -> std::convertible_to<T>;\r\n};\r\n\r\n// \u81ea\u5b9a\u4e49 concept\uff1a\u8981\u6c42\u7c7b\u578b\u652f\u6301\u8f93\u51fa\u5230\u6d41\r\ntemplate<typename T>\r\nconcept Printable = requires(T a, std::ostream& os) {\r\n    { os << a } -> std::same_as<std::ostream&>;\r\n};\r\n\r\n// \u81ea\u5b9a\u4e49 concept\uff1a\u8981\u6c42\u7c7b\u578b\u50cf\u5bb9\u5668\u4e00\u6837\u53ef\u4ee5\u904d\u5386\r\ntemplate<typename T>\r\nconcept Container = requires(T c) {\r\n    { c.begin() } -> std::input_or_output_iterator;\r\n    { c.end() } -> std::input_or_output_iterator;\r\n    { c.size() } -> std::convertible_to<std::size_t>;\r\n};\r\n\r\nvoid basic_usage() {\r\n    std::cout << "--- \u57fa\u7840\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // \u4f7f\u7528 Addable concept\r\n    auto sum = []<Addable T>(T a, T b) -> T {\r\n        return a + b;\r\n    };\r\n\r\n    std::cout << "\u6574\u6570\u76f8\u52a0: " << sum(10, 20) << "\\n";\r\n    std::cout << "\u6d6e\u70b9\u76f8\u52a0: " << sum(1.5, 2.5) << "\\n";\r\n    std::cout << "\u5b57\u7b26\u4e32\u62fc\u63a5: " << sum(std::string("Hello, "), std::string("World!")) << "\\n";\r\n\r\n    // \u4f7f\u7528 Printable concept\r\n    auto display = []<Printable T>(const T& value) {\r\n        std::cout << "\u53ef\u6253\u5370\u503c: " << value << "\\n";\r\n    };\r\n\r\n    display(42);\r\n    display(3.14);\r\n    display(std::string("C++20"));\r\n\r\n    // \u4f7f\u7528 Container concept\r\n    auto print_size = []<Container C>(const C& container) {\r\n        std::cout << "\u5bb9\u5668\u5927\u5c0f: " << container.size() << "\\n";\r\n    };\r\n\r\n    std::vector<int> v = {1, 2, 3, 4, 5};\r\n    std::string s = "Hello";\r\n    print_size(v);\r\n    print_size(s);\r\n}\r\n\r\n// ===================== advanced_usage() =====================\r\n\r\n// ---- concept \u7ec4\u5408 (&&, ||) ----\r\n\r\n// \u4f7f\u7528 && \u7ec4\u5408\uff1a\u540c\u65f6\u6ee1\u8db3\u4e24\u4e2a\u7ea6\u675f\r\ntemplate<typename T>\r\nconcept PrintableAndAddable = Printable<T> && Addable<T>;\r\n\r\n// \u4f7f\u7528 || \u7ec4\u5408\uff1a\u6ee1\u8db3\u5176\u4e2d\u4e00\u4e2a\u7ea6\u675f\u5373\u53ef\r\ntemplate<typename T>\r\nconcept NumberLike = std::integral<T> || std::floating_point<T>;\r\n\r\n// ---- concept \u7ec6\u5316 (refinement) ----\r\n\r\n// \u57fa\u7840 concept\uff1a\u652f\u6301\u76f8\u7b49\u6bd4\u8f83\r\ntemplate<typename T>\r\nconcept EqualityComparable = requires(T a, T b) {\r\n    { a == b } -> std::convertible_to<bool>;\r\n    { a != b } -> std::convertible_to<bool>;\r\n};\r\n\r\n// \u7ec6\u5316 concept\uff1a\u5728\u76f8\u7b49\u6bd4\u8f83\u7684\u57fa\u7840\u4e0a\uff0c\u589e\u52a0\u6392\u5e8f\u6bd4\u8f83\r\ntemplate<typename T>\r\nconcept Ordered = EqualityComparable<T> && requires(T a, T b) {\r\n    { a < b }  -> std::convertible_to<bool>;\r\n    { a > b }  -> std::convertible_to<bool>;\r\n    { a <= b } -> std::convertible_to<bool>;\r\n    { a >= b } -> std::convertible_to<bool>;\r\n};\r\n\r\n// \u66f4\u8fdb\u4e00\u6b65\u7ec6\u5316\uff1a\u6709\u754c\u7684\u6709\u5e8f\u7c7b\u578b\r\ntemplate<typename T>\r\nconcept BoundedOrdered = Ordered<T> && requires {\r\n    { std::numeric_limits<T>::min() } -> std::same_as<T>;\r\n    { std::numeric_limits<T>::max() } -> std::same_as<T>;\r\n};\r\n\r\n// ---- subsumption \u89c4\u5219\u6f14\u793a ----\r\n// \u5f53\u591a\u4e2a\u91cd\u8f7d\u90fd\u6ee1\u8db3\u65f6\uff0c\u7f16\u8bd1\u5668\u9009\u62e9\u7ea6\u675f\u66f4\u4e25\u683c\u7684\u7248\u672c\r\n\r\n// \u7248\u672c1\uff1a\u53ea\u8981\u6c42\u53ef\u6bd4\u8f83\r\ntemplate<EqualityComparable T>\r\nstd::string describe_type(T) {\r\n    return "\u53ef\u6bd4\u8f83\u7c7b\u578b";\r\n}\r\n\r\n// \u7248\u672c2\uff1a\u8981\u6c42\u6709\u5e8f\uff08\u66f4\u4e25\u683c\uff0c\u56e0\u4e3a Ordered \u5305\u542b EqualityComparable\uff09\r\ntemplate<Ordered T>\r\nstd::string describe_type(T) {\r\n    return "\u6709\u5e8f\u7c7b\u578b";\r\n}\r\n\r\n// \u7248\u672c3\uff1a\u8981\u6c42\u6709\u754c\u6709\u5e8f\uff08\u6700\u4e25\u683c\uff09\r\ntemplate<BoundedOrdered T>\r\nstd::string describe_type(T) {\r\n    return "\u6709\u754c\u6709\u5e8f\u7c7b\u578b";\r\n}\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- \u9ad8\u7ea7\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // concept \u7ec4\u5408\u6f14\u793a\r\n    auto add_and_print = []<PrintableAndAddable T>(T a, T b) {\r\n        T result = a + b;\r\n        std::cout << "\u7ed3\u679c: " << result << "\\n";\r\n    };\r\n\r\n    add_and_print(10, 20);\r\n    add_and_print(std::string("C++"), std::string("20"));\r\n\r\n    auto process_number = []<NumberLike T>(T value) {\r\n        std::cout << "\u5904\u7406\u6570\u5b57: " << value << " (\u5927\u5c0f: " << sizeof(T) << " \u5b57\u8282)\\n";\r\n    };\r\n\r\n    process_number(42);\r\n    process_number(3.14);\r\n    process_number(static_cast<short>(7));\r\n\r\n    // subsumption \u6f14\u793a\r\n    std::cout << "\\n-- Subsumption \u89c4\u5219\u6f14\u793a --\\n";\r\n    std::cout << "int \u7c7b\u578b: " << describe_type(42) << "\\n";       // \u9009\u62e9\u6700\u4e25\u683c\u7684 BoundedOrdered\r\n    std::cout << "double \u7c7b\u578b: " << describe_type(3.14) << "\\n";  // \u9009\u62e9 BoundedOrdered\r\n\r\n    // concept \u7ec6\u5316\u94fe\u5c55\u793a\r\n    std::cout << "\\n-- Concept \u7ec6\u5316\u94fe --\\n";\r\n    std::cout << "EqualityComparable<int>: "\r\n              << std::boolalpha << EqualityComparable<int> << "\\n";\r\n    std::cout << "Ordered<int>: "\r\n              << Ordered<int> << "\\n";\r\n    std::cout << "BoundedOrdered<int>: "\r\n              << BoundedOrdered<int> << "\\n";\r\n    std::cout << "BoundedOrdered<std::string>: "\r\n              << BoundedOrdered<std::string> << "\\n";  // false\uff0cstring \u6ca1\u6709 numeric_limits\r\n}\r\n\r\n// ===================== pitfalls() =====================\r\n\r\n// \u9677\u96311\u6f14\u793a\uff1aconcept \u4e2d\u7684\u77ed\u8def\u6c42\u503c\r\ntemplate<typename T>\r\nconcept HasValueType = requires { typename T::value_type; };\r\n\r\ntemplate<typename T>\r\nconcept IterableContainer = HasValueType<T> && requires(T c) {\r\n    { c.begin() };\r\n    { c.end() };\r\n};\r\n// \u5982\u679c T \u6ca1\u6709 value_type\uff0c&& \u4f1a\u77ed\u8def\uff0c\u4e0d\u4f1a\u68c0\u67e5 begin()/end()\r\n\r\n// \u9677\u96312\u6f14\u793a\uff1aconcept \u4e0d\u68c0\u67e5\u8bed\u4e49\uff0c\u53ea\u68c0\u67e5\u8bed\u6cd5\r\ntemplate<typename T>\r\nconcept Hashable = requires(T a) {\r\n    { std::hash<T>{}(a) } -> std::convertible_to<std::size_t>;\r\n};\r\n\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- \u6613\u9519\u70b9 ---\\n\\n";\r\n\r\n    // \u9677\u96311\uff1aconcept \u7ec4\u5408\u7684\u77ed\u8def\u6c42\u503c\r\n    std::cout << "1. concept \u7ec4\u5408\u4f7f\u7528\u77ed\u8def\u6c42\u503c:\\n";\r\n    std::cout << "   HasValueType<int>: " << std::boolalpha << HasValueType<int> << "\\n";\r\n    std::cout << "   HasValueType<vector<int>>: " << HasValueType<std::vector<int>> << "\\n";\r\n    std::cout << "   IterableContainer<int>: " << IterableContainer<int> << "\\n";\r\n    std::cout << "   (int \u6ca1\u6709 value_type\uff0c&& \u77ed\u8def\uff0c\u4e0d\u68c0\u67e5 begin/end)\\n\\n";\r\n\r\n    // \u9677\u96312\uff1aconcept \u53ea\u68c0\u67e5\u8bed\u6cd5\u6709\u6548\u6027\uff0c\u4e0d\u4fdd\u8bc1\u8bed\u4e49\u6b63\u786e\r\n    std::cout << "2. concept \u53ea\u68c0\u67e5\u8868\u8fbe\u5f0f\u662f\u5426\u5408\u6cd5\uff08\u8bed\u6cd5\uff09\uff0c\u4e0d\u68c0\u67e5\u884c\u4e3a\u662f\u5426\u6b63\u786e\uff08\u8bed\u4e49\uff09\\n";\r\n    std::cout << "   \u4f8b\u5982\uff1a\u67d0\u7c7b\u578b\u7684 operator< \u53ef\u80fd\u4e0d\u6ee1\u8db3\u4e25\u683c\u5f31\u5e8f\uff0c\\n";\r\n    std::cout << "   \u4f46 Ordered concept \u4ecd\u7136\u4f1a\u901a\u8fc7\\n\\n";\r\n\r\n    // \u9677\u96313\uff1aconcept \u4e0d\u80fd\u9012\u5f52\r\n    std::cout << "3. concept \u5b9a\u4e49\u4e0d\u80fd\u76f4\u63a5\u9012\u5f52\u5f15\u7528\u81ea\u8eab\\n";\r\n    std::cout << "   \u9700\u8981\u501f\u52a9\u95f4\u63a5\u65b9\u5f0f\uff08\u5982\u8f85\u52a9\u6a21\u677f\uff09\u6765\u5b9e\u73b0\u9012\u5f52\u7ea6\u675f\\n\\n";\r\n\r\n    // \u9677\u96314\uff1asubsumption \u53ea\u5728\u539f\u5b50\u7ea6\u675f\u76f8\u540c\u65f6\u624d\u751f\u6548\r\n    std::cout << "4. Subsumption \u8981\u6c42\u7ea6\u675f\u4e2d\u4f7f\u7528\u76f8\u540c\u7684\u539f\u5b50 concept \u8868\u8fbe\u5f0f\\n";\r\n    std::cout << "   \u5982\u679c\u4e24\u4e2a concept \u867d\u7136\u903b\u8f91\u7b49\u4ef7\u4f46\u5199\u6cd5\u4e0d\u540c\uff0c\\n";\r\n    std::cout << "   \u7f16\u8bd1\u5668\u4e0d\u4f1a\u8ba4\u4e3a\u5b83\u4eec\u6709\u5305\u542b\u5173\u7cfb\\n";\r\n}\r\n\r\n// ===================== main() =====================\r\nint main() {\r\n    std::cout << "===== \u81ea\u5b9a\u4e49 Concepts \u4e0e\u7ec4\u5408\u7ea6\u675f - C++20 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,c.jsx)(e.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,c.jsxs)(e.ul,{children:["\n",(0,c.jsx)(e.li,{children:(0,c.jsx)(e.a,{href:"https://en.cppreference.com/w/cpp/language/constraints",children:"cppreference: Concepts \u9ad8\u7ea7 (\u81ea\u5b9a\u4e49 concept\u3001\u7ec4\u5408\u7ea6\u675f)"})}),"\n"]})]})}function l(n={}){const{wrapper:e}={...(0,s.R)(),...n.components};return e?(0,c.jsx)(e,{...n,children:(0,c.jsx)(i,{...n})}):i(n)}},28453(n,e,r){r.d(e,{R:()=>o,x:()=>a});var t=r(96540);const c={},s=t.createContext(c);function o(n){const e=t.useContext(s);return t.useMemo(function(){return"function"==typeof n?n(e):{...e,...n}},[e,n])}function a(n){let e;return e=n.disableParentContext?"function"==typeof n.components?n.components(c):n.components||c:o(n.components),t.createElement(s.Provider,{value:e},n.children)}}}]);